package x509

import (
	"encoding/hex"
	"testing"
)

var MLDSA44KeyTests = []struct {
	derHex      string
	shouldParse bool
}{
	// Seed Only
	{"802039145bf02902796133d81bd2d8bc4dd401d79fbc9c3f09660f83c80b587ac394", true},
	// Expanded Key
	{"", true},
	// Both Seed and Expanded Key
	{"", true},
	// Invalid Seed case where the Seed is only 31 bytes instead of 32
	{"801f39145bf02902796133d81bd2d8bc4dd401d79fbc9c3f09660f83c80b587ac3", false},
}

var MLDSA65KeyTests = []struct {
	derHex      string
	shouldParse bool
}{
	// Seed Only
	{"8020412ab6afd0ebb891ad2bdfa630cd218c512f12a8c600b20ecca43b23d1ca72b4", true},
	// Expanded Key
	{"", true},
	// Both Seed and Expanded Key
	{"", true},
	// Invalid Expanded Key case where Key length is Key length - 1
	{"", false},
}

var MLDSA87KeyTests = []struct {
	derHex      string
	shouldParse bool
}{
	// Seed Only
	{"802066e2e8de07c33e04280fdd27572f77b5eff83526e026bbe5ff9acfa4f36d094b", true},
	// Expanded Key
	{"", true},
	// Both Seed and Expanded Key
	{"", true},
	// Invalid "Both" case where Seed and Expanded private key correspond to different keys
	{"", false},
}

func TestParseMLDSA44PrivateKey(t *testing.T) {
	for i, test := range MLDSA44KeyTests {
		derBytes, err := hex.DecodeString(test.derHex)
		if err != nil {
			t.Fatalf("#%d: failed to decode MLDSA44 private key: %s", i, err)
		}
		_, err = ParseMLDSA44PrivateKey(derBytes)
		if test.shouldParse {
			if err != nil {
				t.Errorf("#%d: failed to parse valid MLDSA44 private key: %v", i, err)
			}
		} else {
			if err == nil {
				t.Errorf("#%d: parsed invalid MLDSA44 private key", i)
			}
		}
	}
}

